// Only define the Jdump namespaces if not defined.

var Jdump = Jdump || {};

Jdump.Tree = Jdump.Tree || {};

(function () {
	"use strict";

	Jdump.Timeout = 0;

Jdump.Init = function() {

//	let JTooltips = new Tips($$('.hasTip'), { maxTitleChars: 50, fixed: false});

	Jdump.Refresh     = document.getElementById('dumpRefresh'),
	Jdump.Lock        = document.getElementById('dumpLock'),
	Jdump.Locked      = document.getElementById('dumpLocked'),
	Jdump.ExpandAll   = document.getElementById('dumpExpandAll'),
	Jdump.CollapseAll = document.getElementById('dumpCollapseAll');

	Jdump.PopOver     = [].slice.call(document.getElementsByClassName('jdump-popover'));

	Jdump.addListeners();
}

Jdump.addListeners = function (){

	if (Jdump.Locked){

		Jdump.Locked.addEventListener('click', function() {
			return false;
		});
	}

	Jdump.Lock.addEventListener('click', Jdump.LockWindow);

	Jdump.Refresh.addEventListener('click', function() {
		window.location.reload(true);
	});

	if (Jdump.ExpandAll){

		Jdump.ExpandAll.addEventListener('click', function(){
			Jdump.Tree.expandAll('dhtmlgoodies_tree');
		});
	}

	if (Jdump.CollapseAll) {

		Jdump.CollapseAll.addEventListener('click', function(){
			Jdump.Tree.collapseAll('dhtmlgoodies_tree');
		});
	}

	if (Jdump.PopOver.length) {

		for (var i = 0, l = Jdump.PopOver.length; i < l; i++) {

			Jdump.PopOver[i].addEventListener('click', function(){
				renderMessages(this, Jdump.Timeout);
			});
		}
	}
};

Jdump.LockWindow = function () {

	Jdump.Refresh.style.display = 'none';
	Jdump.Lock.style.display = 'none';
	Jdump.Locked.style.display = 'inline-block';
	window.name='dumpLock' + new Date().getTime(); // Make a new unique name for the window
};

let renderMessages = function(e, timeout) {

	let messageContainer = document.getElementById('system-message-container');

	// Check if open
	if(document.getElementById(e.dataset.id)){
		return;
	}

	// Create the alert box
	let messagesBox = document.createElement( 'div' );

	messagesBox.className = 'alert info';
	messagesBox.id = e.dataset.id;

	// Close button
	let buttonWrapper = document.createElement( 'button' );
	buttonWrapper.setAttribute('type', 'button');
	buttonWrapper.setAttribute('data-dismiss', 'alert');
	buttonWrapper.className = 'close';
	buttonWrapper.innerHTML = '×';
	messagesBox.appendChild( buttonWrapper );

	// Title
	let title = 'Source';

	let titleWrapper = document.createElement( 'h4' );
	titleWrapper.className = 'alert-heading';
	titleWrapper.innerHTML = title;
	messagesBox.appendChild(titleWrapper);

	// Add message to the message box
	let messageWrapper = document.createElement( 'div' );
	messageWrapper.className = 'alert-message';
	let message = '<label>Class</label><p class="sclass">' + e.dataset.cls + '</p>' +
	 '<label>Function</label><p class="sfunction">' + e.dataset.func +'</p>' +
	 '<label>File</label><p class="sfile">' + e.dataset.file +'</p>' +
	 '<label>Line</label><p class="sline">' + e.dataset.line +'</p>';
	messageWrapper.innerHTML = message;

	messagesBox.appendChild( messageWrapper );

	messageContainer.appendChild( messagesBox );

	// Shpould create q fado in
	messagesBox.style.opacity = '1';

	let createdMessage = document.getElementById(e.dataset.id);
	// Add close event
	createdMessage.addEventListener('click', function(event){
		removeMessage(this);
	});

	if (timeout && parseInt(timeout) > 0) {
		// Shpould create q fado out
		//createdMessage.style.opacity = '0.5';
		setTimeout(function () {
			removeMessage(createdMessage);
		}, timeout);
	}
};

let removeMessage = function(container) {
	container.remove();
}

document.addEventListener("DOMContentLoaded", function(){

	Jdump.Timeout = Number( dumpCloseTimeout ) * 1000;
	Jdump.Init();
});

})();
